### Listing Sandboxes with Pagination in JavaScript and Python SDKs

Source: https://github.com/e2b-dev/e2b/blob/main/apps/web/src/app/(docs)/docs/migration/v2/page.mdx

Demonstrates the new paginated API for listing sandboxes using `Sandbox.list()` in both JavaScript and Python SDKs, including iteration and querying with metadata.

```javascript
import { Sandbox, SandboxInfo } from '@e2b/code-interpreter'

// Get paginator
const paginator = Sandbox.list()

// Iterate through all sandboxes
for (const sandbox of await paginator.nextItems()) {
    console.log(sandbox.sandboxId)
}

// Iterate through all sandboxes
const allSandboxes: SandboxInfo[] = []
while (paginator.hasNext) {
    const items = await paginator.nextItems()
    allSandboxes.push(...items)
}

// With query
const queryPaginator = Sandbox.list({query: {metadata: {key: "value"}}})
```

```python
from e2b_code_interpreter import Sandbox, SandboxQuery

# Get paginator
paginator = Sandbox.list()

# Iterate through all sandboxes
while paginator.has_next:
    sandboxes = paginator.next_items()
    print(sandboxes)

# With query
paginator = Sandbox.list(query=SandboxQuery(metadata={"key": "value"}))
```

